mcqs.question:
What is the output of the following code?

class Base {
public:
    virtual void show() { std::cout << "Base"; }
};

class Derived : public Base {
public:
    void show() override { std::cout << "Derived"; }
};

int main() {
    Base* ptr = new Derived();
    ptr->show();
    delete ptr;
    return 0;
}

Consider the following code:

class Animal {
public:
    virtual void speak() = 0;
    virtual ~Animal() {}
};

class Dog : public Animal {
public:
    void speak() override { std::cout << "Bark"; }
};

class Cat : public Animal {
public:
    void speak() override { std::cout << "Meow"; }
};

void makeSpeak(Animal& a) { a.speak(); }

int main() {
    Dog d; Cat c;
    makeSpeak(d);
    makeSpeak(c);
    return 0;
}

What is the mechanism that allows the correct speak() function to be called for each animal type?

What will be the output of the following code and why?

class Base {
public:
    virtual ~Base() { std::cout << "Base "; }
};

class Derived : public Base {
public:
    ~Derived() { std::cout << "Derived "; }
};

int main() {
    Base* ptr = new Derived();
    delete ptr;
    return 0;
}

Given the class hierarchy, what is the result of the following dynamic_cast?

class Base { virtual void foo() {} };
class Derived : public Base { void foo() {} };
class Unrelated { };

int main() {
    Base* b = new Derived();
    Derived* d = dynamic_cast<Derived*>(b);
    Unrelated* u = dynamic_cast<Unrelated*>(b);
    // What are d and u respectively?
}

